   /// &lt;summary&gt;
    /// 冒泡排序 /// &lt;/summary&gt;
    public class bubblesort
    &#123; public void BubbleSort(int\[\] R)
        &#123; int i, j, temp; //交换标志 
            bool exchange; for (i = 0; i &lt; R.Length; i++) //最多做R.Length-1趟排序 

 {                    exchange = false; &#x2F;&#x2F;本趟排序开始前，交换标志应为假                    for (j &#x3D; R.Length - 2; j &gt;&#x3D; i; j–)                    { if (R[j + 1] &lt; R[j])　&#x2F;&#x2F;交换条件 {                            temp = R[j + 1];                            R[j + 1] &#x3D; R[j];                            R[j] = temp;                            exchange = true; &#x2F;&#x2F;发生了交换，故将交换标志置为真 }                    } if (!exchange) &#x2F;&#x2F;本趟排序未发生交换，提前终止算法 { break;                    }                }            }        }

