高速排序using System;using System.Collections.Generic;using System.Linq;using System.Text;namespace sorter&#123;public class QuickSorter&#123;private void swap(ref int l, ref int r)&#123;int temp;temp = l;l = r;r = temp;&#125;public void Sort(int[] list, int low, int high)&#123;int pivot;int l, r;int mid;if (high &lt;= low)&#123;return;&#125;else if (high == low + 1)&#123;if (list[low] &gt; list[high])&#123;swap(ref list[low], ref list[high]);&#125;return;&#125;mid = (low + high) &gt;&gt; 1;pivot = list[mid];swap(ref list[low], ref list[mid]);l = low + 1;r = high;do&#123;while (l &lt;= r &amp;&amp; list[l] &lt; pivot)&#123;l++;&#125;while (list[r] &gt;= pivot)&#123;r--;&#125;if (l &lt; r)&#123;swap(ref list[l], ref list[r]);&#125;&#125; while (l &lt; r);list[low] = list[r];list[r] = pivot;if (low + 1 &lt; r)&#123;Sort(list, low, r - 1);&#125;if (r + 1 &lt; high)&#123;Sort(list, r + 1, high);&#125;&#125;&#125;class Program&#123;static void Main(string[] args)&#123;int[] arrInt = new int[] &#123; 4, 2, 7, 1, 8, 3, 9, 0, 5, 6 &#125;;QuickSorter selSor = new QuickSorter();selSor.Sort(arrInt, 0, arrInt.Length - 1);foreach (int i in arrInt)&#123;Console.WriteLine(i);&#125;Console.ReadKey();&#125;&#125;&#125;

