ft + ENumb - 1;if (middle &gt;= Array.Length)&#123;middle = index;&#125;int mergeindex = index;int right;int middleTwo = (index + ENumb - 1) + 1;right = index + ENumb + ENumb - 1;if (right &gt;= Array.Length - 1)&#123;right = Array.Length - 1;&#125;while (left &lt;= middle &amp;&amp; middleTwo &lt;= right)&#123;merge[mergeindex++] = Array[left] &gt;= Array[middleTwo] ? Array[middleTwo++] : Array[left++];&#125;if (left &lt;= middle)&#123;while (left &lt;= middle &amp;&amp; mergeindex &lt; merge.Length)merge[mergeindex++] = Array[left++];&#125;if (middleTwo &lt;= right)&#123;while (middleTwo &lt;= right)merge[mergeindex++] = Array[middleTwo++];&#125;if (right + 1 &gt;= Array.Length)Copy(Array, merge);&#125;public void NaturalMergeSort(int[] Array)&#123;int[,] PointsSymbol = LinearPoints(Array);if (PointsSymbol[0, 1] == Array.Length - 1)return;elseNaturalMerge(Array, PointsSymbol);&#125;public void NaturalMerge(int[] Array, int[,] PointsSymbol)&#123;int left;int right;int leftend;int rightend;mergerows = GNumberTwo(Groups);CopyGroups = Groups;int[] TempArray = new int[Array.Length];while (true)&#123;int[,] TempPointsSymbol = new int[mergerows, 2];int row = 0;do&#123;if (row != CopyGroups - 1)&#123;left = PointsSymbol[row, 0];leftend = PointsSymbol[row, 1];right = PointsSymbol[row + 1, 0];rightend = PointsSymbol[row + 1, 1];MergeThree(Array, TempArray, left, leftend, right, rightend);MergePointSymbol(PointsSymbol, TempPointsSymbol, row);&#125;else&#123;默认剩下的单独一个子数组已经虚拟合并。然后Copy进TempArray。int TempRow = PointsSymbol[row, 0];int TempCol = PointsSymbol[row, 1];while (TempRow &lt;= TempCol)TempArray[TempRow] = Array[TempRow++];TempPointsSymbol[row / 2, 0] = PointsSymbol[row, 0];TempPointsSymbol[row / 2, 1] = PointsSymbol[row, 1];break;&#125;row += 2;if (TempPointsSymbol[0, 1] == Array.Length - 1)break;&#125;while (row &lt;= CopyGroups - 1);Copy(Array, TempArray);UpdatePointSymbol(PointsSymbol, TempPointsSymbol, row);mergerows = GNumber(mergerows);CopyGroups = GNumberTwo(Copy