pprove(amount);        &#125;        else        &#123;            Console.WriteLine($&quot;【部门经理审批】&#123;amount&#125;元超出权限，无后续审批者，拒绝。&quot;);        &#125;    &#125;&#125;/// &lt;summary&gt;具体处理者3：总监（≤10000元）&lt;/summary&gt;public class Director : Approver&#123;    public override void Approve(int amount)    &#123;        if (amount &lt; 0)        &#123;            Console.WriteLine(&quot;错误：申请金额不能为负数，请核对后重新提交！&quot;);            return;        &#125;        if (amount &lt;= 10000)        &#123;            Console.WriteLine($&quot;【总监审批】&#123;amount&#125;元（≤10000元），审批通过。&quot;);        &#125;        else if (_nextApprover != null)        &#123;            Console.WriteLine($&quot;【总监审批】&#123;amount&#125;元超出权限（≤10000元），转发至下一级。&quot;);            _nextApprover.Approve(amount);        &#125;        else        &#123;            Console.WriteLine($&quot;【总监审批】&#123;amount&#125;元超出最高权限，拒绝。&quot;);        &#125;    &#125;&#125;// 客户端：构建链路并测试class Program&#123;    static void Main(string[] args)    &#123;        try        &#123;            // 创建审批者并串联链路            Approver groupLeader = new GroupLeader();            Approver deptManager = new DepartmentManager();            Approver director = new Director();            groupLeader.SetNext(deptManager);            deptManager.SetNext(director);            // 测试不同场景            Console.WriteLine(&quot;=== 测试1：800元小额申请 ===&quot;);            groupLeader.Approve(800);            Console.WriteLine(&quot;
