        以下方法中都是由监控线程中的事件委托方法，应该使用BeginInvoke方法，这样可以优雅的结束线程，如果使用Invoke方法，则调用方式为同步调用，此时如果使用Thread.Join()方法终止线程将引发死锁（正常播放没有问题），Thread.Join()方法的使用使调用线程阻塞等待当前线程完成，在这里即UI线程阻塞等待监控线程完成，而监控线程中又触发UI线程中pictureBox的刷新，使用Invoke方法就造成了监控线程等待UI线程刷新结果，而UI线程已经阻塞，形成了死锁。死锁时只能用Thread.Abort()方法才能结束线程。或者直接强制结束应用程序。
        使用BeginInvoke方法时为异步调用，监控线程不等待刷新结果直接继续执行，可以正常结束。结束后UI才进行刷新，不会造成死锁。

图2.线程关系
/// &lt;summary&gt;/// 刷新UI线程的pixtureBox的方法。/// &lt;/summary&gt;/// &lt;param name=&quot;frame&quot;&gt;要刷新的帧。&lt;/param&gt;private void RefreshFrame(Bitmap frame)&#123;    this.pictureBox.Image = frame;    // 这里一定不能刷新！2012年8月2日1:50:16    //this.pictureBox.Refresh();&#125;/// &lt;summary&gt;/// 响应pictureBox刷新。/// &lt;/summary&gt;/// &lt;param name=&quot;sender&quot;&gt;&lt;/param&gt;/// &lt;param name=&quot;e&quot;&gt;&lt;/param&gt;private void OnRefreshFrame(object sender, FrameRefreshEventArgs e)&#123;    // 判断是否需要跨线程调用    if (this.pictureBox.InvokeRequired == true)    &#123;        FrameRefreshDelegate fresh = this.RefreshFrame;        this.BeginInvoke(fresh, e.Frame);    &#125;    else    &#123;        this.RefreshFrame(e.Frame);    &#125;&#125;/// &lt;summary&gt;/// 响应Label刷新信息。/// &lt;/summary&gt;/// &lt;param name=&quot;sender&quot;&gt;&lt;/param&gt;/// &lt;param name=&quot;e&quot;&gt;&lt;/param&gt;private void OnCompleted(object sender, CompletedEventArgs e)&#123;    // 判断是否需要跨线程调用    CompletedDelegate fresh = this.RefreshStatus;    string message = &quot;视频结束，共 &quot; + e.FrameCount + &quot; 帧。&quot;;    this.BeginInvoke(fresh, message);&#125;　　        关闭时需要中止播放线程之后再退出：/// &lt;summary&gt;/// 关闭窗体时发生。/// &lt;/summary&gt;/// &lt;param name=&quot;sender&quot;&gt;&lt;/param&gt;/// &lt;param name=&quot;e&quot;&gt;&lt;/param&gt;private void OnFormClosed(object sender, FormClosedEventArgs e)&#123;    // 检测子算法请求终止    surveillant.Cancel();    // 阻塞调用线程直到检测子线程终止    if (threadSurveillance != null)    &#123;        if (threadSurveillance.IsAlive == true)        &#123;            threadSurveillance.Join();        &#125;    &#125;&#125;



        （二）   使用异步委托
        创建线程的一个更简单的方法是定义一个委托，并异步调用它。委托是方法的类型安全的引用。Delegate类还支持异步地调用方法。在后台，Delegate类会创建一个执行任务的线程。
// asynchronous by using a delegatePlayVideoDelegate play = this.PlayVideoFile;IAsyncResult status = play.BeginInvoke(null, null); /// &lt;summary&gt;/// 播放视频文件。/// &lt;/summary&gt;private void PlayVideoFile()&#123;    while (true)    &#123;        Image&lt;Bgr, byte&gt; frame = capture.QueryFrame();        if (frame != null)        &#123;            Image&lt;Gray, byte&gt; grayFrame = frame.Convert&lt;Gray, byte&gt;();            grayFrame.Resize(this.width, this.height, INTER.CV_INTER_CUBIC);            RefreshPictureBoxDelegate fresh = this.RefreshPictureBox;            try            &#123;                this.BeginInvoke(fresh, grayFrame.ToBitmap());            &#125;            catch (ObjectDisposedException ex)            &#123;                Thread.CurrentThread.Abort();            &#125;        &#125;        else        &#123;            break;        &#125;    &#125;&#125; /// &lt;summary&gt;/// 刷新UI线程的pixtureBox的方法。/// &lt;/summary&gt;/// &lt;param name=&quot;frame&quot;&gt;要刷新的帧。&lt;/param&gt;private void RefreshPictureBox(Bitmap frame)&#123;    this.pictureBox.Image = frame;&#125;



        （三）   使用BackgroundWorker组件
        BackgroundWorker类是异步事件的一种实现方案，异步组件可以选择性的支持取消操作，并提供进度信息。RunWorkerAsync()方法启动异步调用。CancelAsync()方法取消。

图3.BackgroundWorker组件
/// &lt;summary&gt;/// 播放视频文件。/// &lt;/summary&gt;/// &lt;param name=&quot;sender&quot;&gt;&lt;/param&gt;/// &lt;param name=&quot;e&quot;&gt;&lt;/param&gt;private void detectItemPlay_Click(object sender, EventArgs e)&#123;    if (this.videoFilePath != null)    &#123;        // run async        this.backgroundWorker.RunWorkerAsync(capture);    &#125;&#125; /// &lt;summary&gt;/// 异步调用。/// &lt;/summary&gt;/// &lt;param name=&quot;sender&quot;&gt;&lt;/param&gt;/// &lt;param name=&quot;e&quot;&gt;&lt;/param&gt;private void OnDoWork(object sender, DoWorkEventArgs e)&#123;    Emgu.CV.Capture capture = e.Argument as Emgu.CV.Capture;    while (!e.Cancel)    &#123;        Image&lt;Bgr, byte&gt; frame = capture.QueryFrame();        if (frame != null)        &#123;            Image&lt;Gray, byte&gt; grayFrame = frame.Convert&lt;Gray, byte&gt;();            grayFrame.Resize(this.width, this.height, INTER.CV_INTER_CUBIC);            if (this.backgroundWorker.CancellationPending == true)            &#123;                e.Cancel = true;                break;            &#125;            else            &#123;                if (this.pictureBox.InvokeRequired == true)                &#123;                    RefreshPictureBoxDelegate fresh = this.RefreshPictureBox;                    this.BeginInvoke(fresh, grayFrame.ToBitmap());                &#125;                else                &#123;                    this.RefreshPictureBox(grayFrame.ToBitmap());                &#125;            &#125;        &#125;        else        &#123;            break;        &#125;    &#125;&#125; /// &lt;summary&gt;/// 关闭窗体时发生。/// &lt;/summary&gt;/// &lt;param name=&quot;sender&quot;&gt;&lt;/param&gt;/// &lt;param name=&quot;e&quot;&gt;&lt;/param&gt;private void MainForm_FormClosed(object sender, FormClosedEventArgs e)&#123;    if (this.backgroundWorker.IsBusy)    &#123;        this.backgroundWorker.CancelAsync();    &#125;&#125;

