Console.WriteLine(&quot; [x] Requesting fib(30)&quot;);
var response = rpcClient.Call(&quot;30&quot;);
Console.WriteLine(&quot; [.] Got &#39;&#123;0&#125;&#39;&quot;, response);

rpcClient.Close();

