package com;import java.util.Date;import org.quartz.DateBuilder;import org.quartz.JobBuilder;import org.quartz.JobDetail;import org.quartz.Scheduler;import org.quartz.SchedulerException;import org.quartz.SchedulerFactory;import org.quartz.SimpleScheduleBuilder;import org.quartz.Trigger;import org.quartz.TriggerBuilder;import org.quartz.impl.StdSchedulerFactory;public class QuartzDemo &#123;public void simpleRun() throws SchedulerException &#123;SchedulerFactory factory = new StdSchedulerFactory();     Date runTime = DateBuilder.evenSecondDateAfterNow();  JobDetail jobDetail = JobBuilder.newJob(DemoJob.class).withIdentity(&quot;demo_job&quot;, &quot;demo_group&quot;).build();Trigger trigger = TriggerBuilder.newTrigger().withIdentity(&quot;demo_trigger&quot;, &quot;demo_group&quot;).startAt(new Date()).withSchedule(SimpleScheduleBuilder.simpleSchedule().withIntervalInSeconds(1).withRepeatCount(5)).build();Scheduler scheduler = factory.getScheduler();scheduler.scheduleJob(jobDetail,trigger);System.out.println(jobDetail.getKey() + &quot; 运行在: &quot; + runTime);   scheduler.start();  &#125;public static void main(String[] args) &#123;QuartzDemo demo = new QuartzDemo();try &#123;demo.simpleRun();&#125; catch (SchedulerException e) &#123;e.printStackTrace();&#125;&#125;&#125;

