package com;import org.quartz.Job;import org.quartz.JobBuilder;import org.quartz.JobDetail;import org.quartz.Scheduler;import org.quartz.SchedulerException;import org.quartz.SchedulerFactory;import org.quartz.SimpleScheduleBuilder;import org.quartz.Trigger;import org.quartz.TriggerBuilder;import org.quartz.impl.StdSchedulerFactory;public class QuartzUtil &#123;private final static String JOB_GROUP_NAME = &quot;QUARTZ_JOBGROUP_NAME&quot;;private final static String TRIGGER_GROUP_NAME = &quot;QUARTZ_TRIGGERGROUP_NAME&quot;;public static void addJob(String jobName, String triggerName, Class&lt;? extends Job&gt; jobClass, int seconds)throws SchedulerException &#123;SchedulerFactory sf = new StdSchedulerFactory();Scheduler sche = sf.getScheduler();JobDetail jobDetail = JobBuilder.newJob(jobClass).withIdentity(jobName, JOB_GROUP_NAME).build();Trigger trigger = TriggerBuilder.newTrigger().withIdentity(triggerName, TRIGGER_GROUP_NAME).startNow().withSchedule(SimpleScheduleBuilder.simpleSchedule().withIntervalInSeconds(seconds).repeatForever()).build();sche.scheduleJob(jobDetail, trigger);sche.start();&#125;public static void main(String[] args) &#123;try &#123;QuartzUtil.addJob(&quot;job1&quot;, &quot;trigger1&quot;, DemoJobOne.class, 2);QuartzUtil.addJob(&quot;Job2&quot;, &quot;trigger2&quot;, DemoJobTwo.class, 5);&#125; catch (SchedulerException e) &#123;e.printStackTrace();&#125;&#125;&#125;

