5、登陆Servlet
package com.cyd.shiro;
import java.io.IOException;
import javax.servlet.ServletException;import javax.servlet.annotation.WebServlet;import javax.servlet.http.HttpServlet;import javax.servlet.http.HttpServletRequest;import javax.servlet.http.HttpServletResponse;
import org.apache.shiro.SecurityUtils;import org.apache.shiro.authc.AuthenticationException;import org.apache.shiro.authc.IncorrectCredentialsException;import org.apache.shiro.authc.UnknownAccountException;import org.apache.shiro.authc.UsernamePasswordToken;import org.apache.shiro.subject.Subject;import org.apache.shiro.web.util.SavedRequest;import org.apache.shiro.web.util.WebUtils;
@WebServlet(name &#x3D; “loginServlet”, urlPatterns &#x3D; “&#x2F;loginController”)public class LoginServlet extends HttpServlet {    @Override    protected void doGet(HttpServletRequest req, HttpServletResponse resp) throws ServletException, IOException {        req.getRequestDispatcher(“login.jsp”).forward(req, resp);    }
@Override
protected void doPost(HttpServletRequest req, HttpServletResponse resp) throws ServletException, IOException &#123;
    System.out.println(LoginServlet.class.toString());
    String error = null;
    String username = req.getParameter(&quot;username&quot;);
    String password = req.getParameter(&quot;password&quot;);
    Subject subject = SecurityUtils.getSubject();
    UsernamePasswordToken token = new UsernamePasswordToken(username, password);
    try &#123;
        subject.login(token); 
    &#125; catch (UnknownAccountException e) &#123; 
        error = &quot;用户名/密码错误&quot;;
    &#125; catch (IncorrectCredentialsException e) &#123;
        error = &quot;用户名/密码错误&quot;;
    &#125; catch (AuthenticationException e) &#123;
        // 其他错误，比如锁定，如果想单独处理请单独catch处理
        error = &quot;其他错误：&quot; + e.getMessage();
    &#125;
    if (error != null) &#123;// 出错了，返回登录页面
        req.setAttribute(&quot;error&quot;, error);
        req.getRequestDispatcher(&quot;login.jsp&quot;).forward(req, resp);
    &#125; else &#123;// 登录成功
        //跳转到拦截登陆前的地址
        SavedRequest request=WebUtils.getSavedRequest(req);
        String url =request.getRequestURI();
        req.getRequestDispatcher(url.substring(url.lastIndexOf(&#39;/&#39;))).forward(req, resp);
    &#125;
&#125;

}

