public class MouseDoubleClickCopyTextBehavior : Behavior {        &#x2F;&#x2F;&#x2F;         &#x2F;&#x2F;&#x2F; 需要复制的内容        &#x2F;&#x2F;&#x2F;         public string CopyText        { get { return (string)GetValue(CopyTextProperty); } set { SetValue(CopyTextProperty, value); }        } public static readonly DependencyProperty CopyTextProperty &#x3D; DependencyProperty.Register(“CopyText”, typeof(string), typeof(MouseDoubleClickCopyTextBehavior), new PropertyMetadata(null)); protected override void OnAttached()        { base.OnAttached();            AssociatedObject.PreviewMouseLeftButtonDown +&#x3D; AssociatedObject_PreviewMouseLeftButtonDown;        } protected override void OnDetaching()        { base.OnDetaching();            AssociatedObject.PreviewMouseLeftButtonDown -&#x3D; AssociatedObject_PreviewMouseLeftButtonDown;        } void AssociatedObject_PreviewMouseLeftButtonDown(object sender, MouseButtonEventArgs e)        { if (e.ClickCount &gt;&#x3D; 2)                Clipboard.SetDataObject(CopyText);        } 

